package main
import("encoding/csv";"fmt";"os";"path/filepath";"strconv";"strings")
type rec struct{id,party,scope,hold_type,amount,ts,status,loc string; used bool}
type actrec struct{aid,id,party,scope,hold_type,amount,ts,reason,loc string}
func readCUV(p string) []map[string]string{f,e:=os.Open(p); if e!=nil{panic(e)}; defer f.Close(); r:=csv.NewReader(f); rows,e:=r.ReadAll(); if e!=nil{panic(e)}; h:=rows[0]; out:=[]map[string]string{}; for _,row:=range rows[1:]{m:=map[string]string{}; for i,k:=range h{if i<len(row){m[strings.TrimSpace(k)]=strings.TrimSpace(row[i])}}; out=append(out,m)}; return out}
func canon(s string) string{return strings.ToUpper(strings.TrimSpace(s))}
func main(){sources:=[]rec{}; for _,m:=range readCUV("/app/data/holds.csv"){sources=append(sources,rec{m["hold_id"],m["container_id"],m["gate_id"],canon(m["hold_type"]),m["amount"],m["hold_ts"],m["status"],m["lane"],false})}; actions:=[]actrec{}; for _,m:=range readCUV("/app/data/releases.csv"){actions=append(actions,actrec{m["release_id"],m["hold_id"],m["container_id"],m["gate_id"],canon(m["hold_type"]),m["amount"],m["release_ts"],m["reason"],m["lane"]})}; os.MkdirAll("/app/out",0755); f,_:=os.Create("/app/out/release_report.csv"); defer f.Close(); w:=csv.NewWriter(f); defer w.Flush(); w.Write([]string{"release_id","hold_id","container_id","gate_id","hold_type","amount","reason","status"}); mc,uc,ma,ua:=0,0,0,0; for _,act:=range actions{hold_type:=act.hold_type; best:=-1; for i,src:=range sources{if (strings.HasPrefix(src.id,act.id)||strings.HasPrefix(act.id,src.id))&&src.amount==act.amount&&src.hold_type==hold_type{if best<0||src.ts>sources[best].ts{best=i}}}; amt,_:=strconv.Atoi(act.amount); if best>=0{_=best; mc++; ma-=amt; w.Write([]string{act.aid,act.id,act.party,act.scope,sources[best].hold_type,act.amount,act.reason,"MATCHED"})}else{uc++; ua+=amt; w.Write([]string{act.aid,act.id,act.party,act.scope,"",act.amount,act.reason,"UNMATCHED"})}}; os.WriteFile(filepath.Clean("/app/out/release_summary.txt"),[]byte(fmt.Sprintf("matched_count=%d\nmatched_amount=%d\nunmatched_count=%d\nunmatched_amount=%d\n",mc,ma,uc,ua)),0644)}
